import { Action } from 'redux-saga';
import createReducer from '~/redux/store/createReducer';

import type {
  AfinzDebitInformation,
  AfinzAccountInformation,
} from '../../../screens/PayMethods/Backdrops/BankDetailsForm/Models';

export const PaymentChangeTypes = {
  PAYMENT_CHANGE_CLEAN: '@dacc/PAYMENT_CHANGE_CLEAN',
  PAYMENT_CHANGE_FAILED: '@dacc/PAYMENT_CHANGE_FAILED',
  PAYMENT_CHANGE_REQUEST: '@dacc/PAYMENT_CHANGE_REQUEST',
  PAYMENT_CHANGE_SUCCESS: '@dacc/PAYMENT_CHANGE_SUCCESS',
} as const;

export interface PaymentChangeReducerProps {
  isError: boolean;
  isLoading: boolean;
}

type State = PaymentChangeReducerProps;

const initialState: PaymentChangeReducerProps = {
  isError: false,
  isLoading: false,
};

const paymentChangeReducer = createReducer(initialState, {
  [PaymentChangeTypes.PAYMENT_CHANGE_REQUEST](state: State): State {
    return { ...state, isLoading: true, isError: false };
  },
  [PaymentChangeTypes.PAYMENT_CHANGE_SUCCESS](state: State): State {
    return { ...state, isLoading: false, isError: false };
  },
  [PaymentChangeTypes.PAYMENT_CHANGE_FAILED](state: State): State {
    return { ...state, isLoading: false, isError: true };
  },
  [PaymentChangeTypes.PAYMENT_CHANGE_CLEAN](): State {
    return initialState;
  },
});

interface PaymentChangeActions {
  putChangePaymentRequest: (
    _payload: AfinzAccountInformation | AfinzDebitInformation,
    _callback: () => Promise<void> | void,
  ) => Action;
  putChangePaymentSuccess: () => Action;
  putChangePaymentFailed: () => Action;
  putChangePaymentClean: () => Action;
}

export const paymentChangeActions: PaymentChangeActions = {
  putChangePaymentRequest: (payload, callback) => ({
    type: PaymentChangeTypes.PAYMENT_CHANGE_REQUEST,
    payload,
    callback,
  }),
  putChangePaymentSuccess: () => ({
    type: PaymentChangeTypes.PAYMENT_CHANGE_SUCCESS,
  }),
  putChangePaymentFailed: () => ({
    type: PaymentChangeTypes.PAYMENT_CHANGE_FAILED,
  }),
  putChangePaymentClean: () => ({
    type: PaymentChangeTypes.PAYMENT_CHANGE_CLEAN,
  }),
};

export default paymentChangeReducer;

