import { Action } from 'redux';
import createReducer from '~/redux/store/createReducer';

export enum DownloadInvoiceTypes {
  REQUEST = '@downloadInvoice/DOWNLOAD_INVOICE_REQUEST',
  SUCCESS = '@downloadInvoice/DOWNLOAD_INVOICE_SUCCESS',
  FAILED = '@downloadInvoice/DOWNLOAD_INVOICE_FAILED',
  CLEAR = '@downloadInvoice/DOWNLOAD_INVOICE_CLEAR',
}

export interface DownloadInvoiceReducerProps {
  isLoading: boolean;
  isError: boolean;
  isSuccessful: boolean;
}

export type DownloadInvoicesCallback = (_data: { base64: string }) => void;

export interface DownloadInvoiceResponse {
  code: number;
  message: string;
  data: string;
}

type State = DownloadInvoiceReducerProps;

const initialState: DownloadInvoiceReducerProps = {
  isLoading: false,
  isError: false,
  isSuccessful: false,
};

const downloadInvoiceReducer = createReducer(initialState, {
  [DownloadInvoiceTypes.REQUEST](state: State) {
    return {
      ...state,
      isLoading: true,
    };
  },
  [DownloadInvoiceTypes.SUCCESS](state: State) {
    return {
      ...state,
      isSuccessful: true,
      isLoading: false,
      isError: false,
    };
  },
  [DownloadInvoiceTypes.FAILED](
    state: State,
    {
      message,
      code,
    }: {
      invoice: any;
      message: string;
      code: number;
    },
  ) {
    return {
      ...state,
      message,
      isSuccessful: false,
      code,
      isLoading: false,
      isError: true,
    };
  },
  [DownloadInvoiceTypes.CLEAR](): State {
    return initialState;
  },
});

export type DownloadInvoiceActions = {
  downloadInvoiceRequest: (
    _cpf: string,
    _date: string,
    _callBack?: DownloadInvoicesCallback,
    _openFile?: boolean,
  ) => Action;
  downloadInvoiceSuccess: () => Action;
  downloadInvoiceFailed: () => Action;
  downloadInvoiceClear: () => Action;
};

export const downloadInvoiceActions: DownloadInvoiceActions = {
  downloadInvoiceRequest: (
    cpf: string,
    date: string,
    callBack?: DownloadInvoicesCallback,
    openFile = true,
  ) => ({
    type: DownloadInvoiceTypes.REQUEST,
    cpf,
    date,
    callBack,
    openFile,
  }),
  downloadInvoiceSuccess: () => ({
    type: DownloadInvoiceTypes.SUCCESS,
  }),
  downloadInvoiceFailed: () => ({
    type: DownloadInvoiceTypes.FAILED,
  }),
  downloadInvoiceClear: () => ({
    type: DownloadInvoiceTypes.CLEAR,
  }),
};

export default downloadInvoiceReducer;

