import { Action } from "redux";
import createReducer from '~/redux/store/createReducer';

export enum InvoiceBarcodeTypes {
  REQUEST = '@invoices/barcode/REQUEST',
  SUCCESS = '@invoices/barcode/SUCCESS',
  FAILED = '@invoices/barcode/FAILED',
  CLEAR = '@invoices/barcode/CLEAR',
}

export type InvoiceBarcodeCallback = (_data: {
  response: InvoiceBarcodeResponseData | undefined;
  statusCode: number | undefined;
}) => void;

export interface InvoiceBarcodeResponseData {
  code: number | undefined;
  message: string;
  data: {
    linhaDigitavel: string;
  };
}

export interface InvoiceBarcodeReducerProps {
  isLoading: boolean;
  isError: boolean;
  statusCode?: number;
  messageError?: string;
  data: {
    code: string;
  };
}

type State = InvoiceBarcodeReducerProps;

const initialState: InvoiceBarcodeReducerProps = {
  isLoading: false,
  isError: false,
  data: {
    code: '',
  },
  messageError: '',
  statusCode: undefined,
};

const invoiceBarcodeReducer = createReducer(initialState, {
  [InvoiceBarcodeTypes.REQUEST](state: State): State {
    return {
      ...state,
      isLoading: true,
    };
  },
  [InvoiceBarcodeTypes.SUCCESS](
    state: State,
    {
      data: { response },
    }: { data: { response: InvoiceBarcodeReducerProps['data'] } },
  ): State {
    return { ...state, isLoading: false, isError: false, data: response };
  },
  [InvoiceBarcodeTypes.FAILED](
    state: State,
    { statusCode, messageError }: { statusCode: number; messageError?: string },
  ): State {
    return {
      ...state,
      isLoading: false,
      isError: true,
      messageError,
      statusCode,
    };
  },
  [InvoiceBarcodeTypes.CLEAR](): State {
    return initialState;
  },
});

interface InvoiceBarcodeActions {
  invoiceBarcodeRequest: (_callback: InvoiceBarcodeCallback) => Action;
  invoiceBarcodeSuccess: (_data: {
    response: InvoiceBarcodeReducerProps['data'];
  }) => Action;
  invoiceBarcodeError: (_statusCode: number, _messageError?: string) => Action;
  invoiceBarcodeClean: () => Action;
}

export const invoiceBarcodeActions: InvoiceBarcodeActions = {
  invoiceBarcodeRequest: callback => ({
    type: InvoiceBarcodeTypes.REQUEST,
    callback,
  }),
  invoiceBarcodeSuccess: data => ({
    type: InvoiceBarcodeTypes.SUCCESS,
    data,
  }),
  invoiceBarcodeError: (statusCode, messageError) => ({
    type: InvoiceBarcodeTypes.FAILED,
    statusCode,
    messageError,
  }),
  invoiceBarcodeClean: () => ({
    type: InvoiceBarcodeTypes.CLEAR,
  }),
};

export default invoiceBarcodeReducer;

